// JSONL event logger
class EventLogger {
  constructor(outputPath) {
    this.outputPath = outputPath;
    this.events = [];
  }

  log(type, message, data = {}, success = null) {
    const event = {
      type,
      timestamp: new Date().toISOString(),
      message,
      data,
      ...(success !== null && { success }),
    };
    this.events.push(event);
    console.log(JSON.stringify(event));
    fs.appendFileSync(this.outputPath, JSON.stringify(event) + '\n');
  }

  start() { this.log('start', 'Scenario execution started'); }
  input(name, value) { this.log('input', `Input: ${name}`, { name, value }); }
  output(name, value) { this.log('output', `Output: ${name}`, { name, value }); }
  assertion(name, passed, expected, actual) {
    this.log('assertion', `Assertion: ${name}`, { expected, actual }, passed);
  }
  cleanup(message) { this.log('cleanup', message); }
  end(success, error = null) {
    this.log('end', success ? 'Scenario passed' : 'Scenario failed', { error }, success);
  }
  error(message, err) { this.log('error', message, { error: err?.message || err }); }
}

