/**
 * Helper: Execute shell command and return output
 */
function execCommand(command, options = {}) {
  try {
    const output = execSync(command, {
      cwd: path.join(__dirname, '../..'),
      encoding: 'utf8',
      stdio: options.silent ? 'pipe' : 'inherit',
      ...options
    });
    return { success: true, output, exitCode: 0 };
  } catch (error) {
    return {
      success: false,
      output: error.stdout || error.stderr || error.message,
      exitCode: error.status || 1,
      error
    };
  }
}

/**
 * Helper: Check if file exists
 */
function fileExists(filePath) {
  const fullPath = path.join(__dirname, '../..', filePath);
  return fs.existsSync(fullPath);
}

/**
 * Helper: Grep for pattern in codebase
 */
function grepCodebase(pattern, options = {}) {
  const baseDir = path.join(__dirname, '../..');
  const searchPath = options.path || 'src';
  const cmd = `grep -r "${pattern}" ${searchPath} || true`;

  try {
    const output = execSync(cmd, {
      cwd: baseDir,
      encoding: 'utf8',
      stdio: 'pipe'
    });

    const matches = output.trim().split('\n').filter(line => line.length > 0);
    return {
      found: matches.length > 0,
      matches,
      count: matches.length
    };
  } catch (error) {
    return {
      found: false,
      matches: [],
      count: 0,
      error: error.message
    };
  }
}

/**
 * Helper: Check environment variables
 */
function checkEnvVars() {
  const baseDir = path.join(__dirname, '../..');
  const envPath = path.join(baseDir, '.env');

  if (!fs.existsSync(envPath)) {
    return { exists: false, vars: {} };
  }

  const envContent = fs.readFileSync(envPath, 'utf8');
  const vars = {};

  envContent.split('\n').forEach(line => {
    const match = line.match(/^([^=]+)=(.*)$/);
    if (match) {
      vars[match[1].trim()] = !!match[2].trim();
    }
  });

  return { exists: true, vars };
}

/**
 * Preflight: Ensure all requirements are ready before running scenarios
 */
async function ensureRequirements(logger) {
  logger.log('info', 'Checking requirements...');

  const checks = {
    projectRoot: false,
    packageJson: false,
    srcDirectory: false,
    envFile: false,
    nodeModules: false,
    buildScript: false
  };

  try {
    // Check project root structure
    const baseDir = path.join(__dirname, '../..');
    checks.projectRoot = fs.existsSync(baseDir);

    // Check package.json
    const packageJsonPath = path.join(baseDir, 'package.json');
    checks.packageJson = fs.existsSync(packageJsonPath);

    // Check src directory
    const srcDir = path.join(baseDir, 'src');
    checks.srcDirectory = fs.existsSync(srcDir);

    // Check .env file
    const envPath = path.join(baseDir, '.env');
    checks.envFile = fs.existsSync(envPath);

    // Check node_modules
    const nodeModulesPath = path.join(baseDir, 'node_modules');
    checks.nodeModules = fs.existsSync(nodeModulesPath);

    // Check if build script exists
    if (checks.packageJson) {
      const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf8'));
      checks.buildScript = !!packageJson.scripts?.build;
    }

    logger.output('requirements_check', checks);

    // All critical checks must pass
    const allPassed = checks.projectRoot && checks.packageJson && checks.srcDirectory;

    if (!allPassed) {
      logger.error('Requirements check failed', checks);
      return false;
    }

    logger.log('info', 'All requirements satisfied');
    return true;

  } catch (error) {
    logger.error('Requirements check error', error);
    return false;
  }
}

async function cleanup(logger) {
  for (const record of createdRecords.reverse()) {
    try {
      // Cleanup based on record type
      switch (record.type) {
        case 'test-file':
          const filePath = path.join(__dirname, '../..', record.id);
          if (fs.existsSync(filePath)) {
            fs.unlinkSync(filePath);
            logger.cleanup(`Deleted test file: ${record.id}`);
          }
          break;
        case 'test-dir':
          const dirPath = path.join(__dirname, '../..', record.id);
          if (fs.existsSync(dirPath)) {
            fs.rmSync(dirPath, { recursive: true });
            logger.cleanup(`Deleted test directory: ${record.id}`);
          }
          break;
        default:
          logger.cleanup(`Cleaned up ${record.type}: ${record.id}`);
      }
    } catch (err) {
      logger.error(`Failed to cleanup ${record.type}: ${record.id}`, err);
    }
  }
}

